int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

// Recursive version
int gcdRecursive(int a, int b) {
    return b == 0 ? a : gcdRecursive(b, a % b);
}

code.python:
def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

# Using recursion
def gcd_recursive(a, b):
    if b == 0:
        return a
    return gcd_recursive(b, a % b)

